import base64,os
FILES={
  'src/app/api/projects/[id]/access-codes/[codeId]/route.ts': '',
  'src/app/api/projects/[id]/members/[memberId]/route.ts': '',
  'src/app/projects/[id]/access/page.tsx': '',
  'src/app/projects/[id]/team/page.tsx': '',
}
for rel,b64 in FILES.items():
    d=os.path.dirname(rel)
    if d: os.makedirs(d,exist_ok=True)
    open(rel,'wb').write(base64.b64decode(b64)); print('ecrit',rel)
